import{c as e,Q as s,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const i="/demo-capture.png",u=JSON.parse('{"title":"Gateway Integration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/gateway.md","filePath":"guide/gateway.md"}'),o={name:"guide/gateway.md"};function l(p,a,r,d,h,c){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="gateway-integration" tabindex="-1">Gateway Integration <a class="header-anchor" href="#gateway-integration" aria-label="Permalink to &quot;Gateway Integration&quot;">​</a></h1><p>The l33t gateway is an optional AI processing backend that enhances your dictation before it reaches your editor — formatting, cleanup, and language model enhancement.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mic → OS Dictation → raw text → Gateway → enhanced text → Editor</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                               Mode-aware routing</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                         ┌───────────┼───────────┐</span></span>
<span class="line"><span>                         ▼           ▼           ▼</span></span>
<span class="line"><span>                    Rules Engine  DeepSeek     OpenAI</span></span>
<span class="line"><span>                       (free)    (cheapest)  (strongest)</span></span></code></pre></div><p>When the gateway is enabled, every utterance goes through a processing pipeline: <strong>authentication → rate limiting → credit check → model selection → processing → response → insert</strong>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://www.docker.com/" target="_blank" rel="noreferrer">Docker</a> and Docker Compose</li><li><a href="https://pnpm.io/" target="_blank" rel="noreferrer">pnpm</a> (<code>corepack enable pnpm</code>)</li><li>Node.js 20+</li></ul><h2 id="starting-the-gateway" tabindex="-1">Starting the Gateway <a class="header-anchor" href="#starting-the-gateway" aria-label="Permalink to &quot;Starting the Gateway&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># From the l33tdev/ monorepo root</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GATEWAY_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dev-key-12345&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span></span></code></pre></div><p>This starts four services:</p><table tabindex="0"><thead><tr><th>Service</th><th>Port</th><th>Purpose</th></tr></thead><tbody><tr><td>Gateway API</td><td>3000</td><td>Processing endpoint</td></tr><tr><td>PostgreSQL</td><td>5432</td><td>Request/response persistence</td></tr><tr><td>Redis</td><td>6379</td><td>Rate limiting cache</td></tr><tr><td>Nginx</td><td>80</td><td>Reverse proxy</td></tr></tbody></table><p><strong>Verify it&#39;s running:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gateway.l33tspeak.dev/health</span></span></code></pre></div><h2 id="enabling-the-gateway" tabindex="-1">Enabling the Gateway <a class="header-anchor" href="#enabling-the-gateway" aria-label="Permalink to &quot;Enabling the Gateway&quot;">​</a></h2><ol><li><strong>Open the Command Palette</strong> (<code>Cmd+Shift+P</code>)</li><li>Run <strong>&quot;L33t Speak: Set Gateway API Key&quot;</strong></li><li>Enter your API key (default: <code>dev-key-12345</code>)</li></ol><p>Setting the API key automatically enables the gateway. No additional config toggle needed.</p><p>You can also control it manually in VS Code settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>l33t-speak.enableGateway</code></td><td><code>false</code></td><td>Toggle gateway processing on/off</td></tr><tr><td><code>l33t-speak.gatewayUrl</code></td><td><code>https://gateway.l33tspeak.dev</code></td><td>Gateway API base URL</td></tr><tr><td><code>l33t-speak.gatewayApiKey</code></td><td><code>&quot;&quot;</code></td><td>Placeholder — actual key stored in OS keychain</td></tr></tbody></table><p>The API key is stored securely in your operating system&#39;s keychain via VS Code&#39;s SecretStorage — never in plaintext settings.</p><h2 id="viewing-gateway-logs" tabindex="-1">Viewing Gateway Logs <a class="header-anchor" href="#viewing-gateway-logs" aria-label="Permalink to &quot;Viewing Gateway Logs&quot;">​</a></h2><p>Every request and response is logged to a dedicated output channel:</p><ol><li>Open the Output panel (<code>Cmd+Shift+U</code>)</li><li>Select <strong>&quot;L33t Gateway&quot;</strong> from the dropdown</li></ol><p>You&#39;ll see:</p><p><img src="`+i+`" alt="Gateway output channel"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[2026-05-29T06:06:13.855Z] POST https://gateway.l33tspeak.dev</span></span>
<span class="line"><span>  Raw text (104 chars): &quot;Create me a skill that looks up data...&quot;</span></span>
<span class="line"><span>Mode: markdown (auto-detected)</span></span>
<span class="line"><span>  Status: 200</span></span>
<span class="line"><span>  Route: rules-engine</span></span>
<span class="line"><span>  Model: unknown</span></span>
<span class="line"><span>  Latency: 0ms</span></span>
<span class="line"><span>  Cost: $0.000000</span></span>
<span class="line"><span>  Processed (105 chars): &quot;Create me a skill that looks up data...&quot;</span></span></code></pre></div><p>For live container logs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span></code></pre></div><h2 id="processing-indicator" tabindex="-1">Processing Indicator <a class="header-anchor" href="#processing-indicator" aria-label="Permalink to &quot;Processing Indicator&quot;">​</a></h2><p>While the gateway processes your dictation, the status bar shows an animated rainbow indicator:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🟥 Enhancing... (red)</span></span>
<span class="line"><span>🟧 Enhancing... (orange)</span></span>
<span class="line"><span>🟨 Enhancing... (yellow)</span></span>
<span class="line"><span>🟩 Enhancing... (green)</span></span>
<span class="line"><span>🟦 Enhancing... (blue)</span></span>
<span class="line"><span>🟪 Enhancing... (purple)</span></span></code></pre></div><p>The background color cycles through the rainbow while a spinner animates. The indicator is blue/cyan for local processing (rules-engine) and full rainbow for hosted LLM calls (DeepSeek/OpenAI).</p><h2 id="one-command-dev-environment" tabindex="-1">One-Command Dev Environment <a class="header-anchor" href="#one-command-dev-environment" aria-label="Permalink to &quot;One-Command Dev Environment&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/start-dev.sh</span></span></code></pre></div><p>This starts Docker, builds the extension, and launches VS Code with the Extension Development Host pre-configured for gateway use.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guide/modes.html">Processing Modes</a> — all 6 modes and how to choose</li><li><a href="/guide/configuration.html">Configuration</a> — all gateway settings</li></ul>`,36)])])}const k=e(o,[["render",l]]);export{u as __pageData,k as default};
